import React, { useState, useEffect, useRef } from 'react';
import { Outlet, useNavigate, useLocation, NavLink } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import axios from 'axios';

const adminNav = [
  { section: 'Overview', items: [{ to: '/admin/dashboard', icon: '📊', label: 'Dashboard' }] },
  { section: 'Management', items: [
    { to: '/admin/students', icon: '👨‍🎓', label: 'Students' },
    { to: '/admin/routes', icon: '🗺️', label: 'Bus Routes' },
    { to: '/admin/fees', icon: '💰', label: 'Fee Records' },
  ]},
  { section: 'Scheduling', items: [
    { to: '/admin/schedules', icon: '📅', label: 'Payment Schedules' },
    { to: '/admin/upcoming', icon: '⏰', label: 'Upcoming Dues' },
    { to: '/admin/overdue', icon: '⚠️', label: 'Overdue Fees' },
  ]},
];

const studentNav = [
  { section: 'My Portal', items: [
    { to: '/student/dashboard', icon: '🏠', label: 'Dashboard' },
    { to: '/student/fees', icon: '💳', label: 'My Fees' },
    { to: '/student/schedule', icon: '📅', label: 'Fee Schedule' },
    { to: '/student/notifications', icon: '🔔', label: 'Notifications', badgeKey: 'notif' },
    { to: '/student/profile', icon: '👤', label: 'My Profile' },
  ]},
];

const pageTitles = {
  '/admin/dashboard': { title: 'Dashboard', sub: 'Overview & Analytics' },
  '/admin/students': { title: 'Students', sub: 'Manage student records' },
  '/admin/routes': { title: 'Bus Routes', sub: 'Manage routes & fares' },
  '/admin/fees': { title: 'Fee Records', sub: 'Collect & track payments' },
  '/admin/schedules': { title: 'Payment Schedules', sub: 'Configure due dates & reminders' },
  '/admin/upcoming': { title: 'Upcoming Dues', sub: 'Fees due in next 30 days' },
  '/admin/overdue': { title: 'Overdue Fees', sub: 'Pending overdue payments' },
  '/student/dashboard': { title: 'My Dashboard', sub: 'Your bus fee overview' },
  '/student/fees': { title: 'My Fees', sub: 'Fee history & receipts' },
  '/student/schedule': { title: 'Fee Schedule', sub: 'Upcoming payment schedule' },
  '/student/profile': { title: 'My Profile', sub: 'Account & route details' },
  '/student/notifications': { title: 'Notifications', sub: 'Alerts & payment reminders' },
};

export default function Layout() {
  const { user, logout, isAdmin } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [showNotif, setShowNotif] = useState(false);
  const notifRef = useRef(null);

  useEffect(() => {
    axios.get('/notifications').then(r => setNotifications(r.data)).catch(() => {});
  }, [location.pathname]);

  useEffect(() => {
    const handler = (e) => { if (notifRef.current && !notifRef.current.contains(e.target)) setShowNotif(false); };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const unread = notifications.filter(n => !n.isRead).length;
  const page = pageTitles[location.pathname] || { title: 'Bus Fees', sub: '' };
  const navGroups = isAdmin ? adminNav : studentNav;

  const handleLogout = () => { logout(); navigate('/login'); };

  const markAllRead = async () => {
    await axios.put('/notifications/read-all');
    setNotifications(n => n.map(x => ({ ...x, isRead: true })));
  };

  const timeAgo = (date) => {
    const diff = Date.now() - new Date(date);
    const m = Math.floor(diff / 60000);
    if (m < 1) return 'just now';
    if (m < 60) return `${m}m ago`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}h ago`;
    return `${Math.floor(h/24)}d ago`;
  };

  return (
    <div className="layout">
      {sidebarOpen && <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)} />}
      <aside className={`sidebar ${sidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-logo">
          <span className="bus-icon">🚌</span>
          <div>
            <h1>Campus Bus</h1>
            <span>{isAdmin ? 'Admin Portal' : 'Student Portal'}</span>
          </div>
        </div>
        <nav className="sidebar-nav">
          {navGroups.map(group => (
            <div key={group.section} className="nav-group">
              <div className="nav-section-label">{group.section}</div>
              {group.items.map(item => (
                <NavLink key={item.to} to={item.to} className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`} onClick={() => setSidebarOpen(false)}>
                  <span className="icon">{item.icon}</span>
                  <span>{item.label}</span>
                  {item.badgeKey === 'notif' && unread > 0 && <span className="nav-badge">{unread}</span>}
                </NavLink>
              ))}
            </div>
          ))}
        </nav>
        <div className="sidebar-footer">
          <div className="user-card">
            <div className="user-avatar">{user?.name?.charAt(0).toUpperCase()}</div>
            <div className="user-info">
              <div className="user-name">{user?.name}</div>
              <div className="user-role">{user?.role}</div>
            </div>
          </div>
          <button className="logout-btn" onClick={handleLogout}>🚪 Sign Out</button>
        </div>
      </aside>

      <main className="main-content">
        <header className="topbar">
          <div className="topbar-left">
            <button className="menu-toggle" onClick={() => setSidebarOpen(true)} aria-label="Open menu">☰</button>
            <div>
              <h2>{page.title}</h2>
              <p>{page.sub}</p>
            </div>
          </div>
          <div className="topbar-right">
            <div className="topbar-search" style={{ display: isAdmin ? 'none' : 'flex' }}>
              <span>🎓</span>
              <span>{user?.name?.split(' ')[0]}</span>
            </div>
            <div style={{ position:'relative' }} ref={notifRef}>
              <button className="notif-btn" onClick={() => setShowNotif(!showNotif)} title="Notifications">
                🔔
                {unread > 0 && <span className="notif-dot" />}
              </button>
              {showNotif && (
                <div className="notif-panel">
                  <div className="notif-header">
                    <span style={{ fontWeight:700, fontSize:14 }}>🔔 Notifications {unread > 0 && <span className="badge badge-overdue" style={{ marginLeft:6 }}>{unread}</span>}</span>
                    {unread > 0 && <button className="btn btn-outline btn-sm" onClick={markAllRead}>Mark all read</button>}
                  </div>
                  <div className="notif-list">
                    {notifications.length === 0 ? (
                      <div style={{ padding:24, textAlign:'center', color:'var(--text-muted)', fontSize:13 }}>No notifications</div>
                    ) : notifications.slice(0, 8).map(n => (
                      <div key={n.id} className={`notif-item ${!n.isRead ? 'unread' : ''}`} onClick={() => { axios.put(`/notifications/${n.id}/read`); setNotifications(prev => prev.map(x => x.id === n.id ? {...x, isRead:true} : x)); }}>
                        <div className="notif-item-title">{n.title}</div>
                        <div className="notif-item-msg">{n.message}</div>
                        <div className="notif-item-time">{timeAgo(n.createdAt)}</div>
                      </div>
                    ))}
                  </div>
                  <div className="notif-footer">
                    {!isAdmin && (
                      <button className="btn btn-primary btn-sm" onClick={() => { setShowNotif(false); navigate('/student/notifications'); }}>View All</button>
                    )}
                    <button className="btn btn-outline btn-sm" onClick={() => setShowNotif(false)}>Close</button>
                  </div>
                </div>
              )}
            </div>
            <div className="topbar-date">
              📅 {new Date().toLocaleDateString('en-IN', { weekday:'short', day:'numeric', month:'short', year:'numeric' })}
            </div>
          </div>
        </header>
        <div className="page-content">
          <Outlet />
        </div>
      </main>
    </div>
  );
}
